%[text] # Analysis of Training Data
%[text:tableOfContents]{"heading":"Table of Contents"}
%%
%[text] ## Import Data
%[text] We have 1610 training samples, I'd like to do some analysis on a random sample of 100 of each class. 
%[text] To do so, we'll import the labels, and randomly select 100 of each label then import those files.
% Add script folder to path so that files are found correctly
mfilePath = mfilename('fullpath');
if contains(mfilePath,'LiveEditorEvaluationHelper')
    mfilePath = fileparts(matlab.desktop.editor.getActiveFilename);
end

if ~contains(mfilePath, ".m")
    mfilePath = fileparts(mfilePath+".m");
    
end

addpath(mfilePath);
addpath(mfilePath+"/../data");
addpath(mfilePath+"/../data/train/");

labelfile = readtable("train_labels.csv");

sample_0_ids = string(labelfile(labelfile.Labels == 0,:).ID);
sample_1_ids = string(labelfile(labelfile.Labels == 1,:).ID);

fprintf( ... %[output:group:42a3990f] %[output:47a3370e]
    "There are %i samples in class 0, and %i in class 1", ... %[output:47a3370e]
    length(sample_0_ids),length(sample_1_ids) ... %[output:47a3370e]
    ); %[output:group:42a3990f] %[output:47a3370e]
%[text] First issue, there's an overrepresentation of class 0 vs class 1! We'll come back to that later.
%[text] Randomly select 100 IDs from each class:
rng(1)
sample_ids(:,1) = sample_0_ids( ...
                    randperm(size(sample_0_ids,1),100) ...
                    );
sample_ids(:,2) = sample_1_ids( ...
                    randperm(size(sample_0_ids,1),100) ...
                    );
%[text] Let's now read the corresponding files:
for class_it = (0:1)+1
    for id_it = 1:size(sample_ids,1)
        filename = mfilePath+"/../data/train/"+sample_ids(id_it,class_it)+'.wav';

        % If data matrix doesnt exist, create it and define fs
        if ~exist("data","var")
            [a,fs] = audioread(fullfile(filename));
            data = cell(size(sample_ids,1),2);
            data(id_it, class_it) = {a};
        % Otherwise, fill existing matrix
        else
            [audio, fs(class_it*size(sample_ids,1) + id_it)] = audioread(fullfile(filename));
            data(id_it, class_it) = {audio};
        end
    end
end
categories(categorical(fs)) %[output:7c2bdcc2]
%[text] Next annoyance, the file sizes are different! At least the sampling frequencies are the same.
fs = mode(fs);
%%
%[text] ## Frequency Analysis
%[text] Let's have a look at a heatmap of the frequency response of each 
N = 4096 % FFT_bins %[output:9d456613]

fft_img = zeros(size(data,1),N);
for class_it = 1:size(data,2) %[output:group:287862c4]
    % Build FFT img 
    for id_it = 1:size(data,1)
        audio_cell = data(id_it,class_it);
        audio = audio_cell{:};
        fft_img(id_it,:) = 10*log10(abs(fft(audio,N)'));
    end

    % Plot w. imagesc
    figure %[output:384d0c00] %[output:2cc5e1aa]
    imagesc(fft_img(:,1:(N/2 +1) )) %[output:384d0c00] %[output:2cc5e1aa]
    xticks(([0.25,0.5,0.75,1]*N/2))
    xticklabels( ...
        [" "+num2str( fs/8 ); num2str( fs/4 ); num2str(3*fs/8); num2str(fs/2)] ...
        );
    xlabel("Frequency")
    ylabel("Sample")
    tit = sprintf("Class %i",class_it-1);
    title(tit)
    colorbar
end %[output:group:287862c4]
%[text] There doesn't seem to be a distinct continuous time frequency difference between the two classes. Let's have a look at the short time fourier transform. We'll grab the first T samples from each, as they're not all the same length.
T = 25000;
T_bins = T/125; % Arbitrary to get a square image

stft_feats = zeros(101*778,size(data,1),2);

for class_it = 1:size(data,2); %[output:group:7c3aa19f]
    % Build FFT img 
    for id_it = 1:size(data,1)
        audio_cell = data(id_it,class_it);
        audio = audio_cell{:};

        [s, f ,t] = stft(audio(1:T),fs,"FFTLength",T_bins, "FrequencyRange","onesided");

        if ~exist("stft_img","var")
            stft_img = zeros(size(s));
        end
        
        stft_img = stft_img + abs(s);
        stft_feats(:,id_it,class_it) = s(:);
    end

    % Plot w. imagesc
    figure %[output:6228f32a] %[output:77a57b13]
    %stft_img(1:10,:) = 0; % High Pass
    imagesc(10*log10(stft_img)) %[output:6228f32a] %[output:77a57b13]
    
    
    fpoints = 1:10:101;
    tpoints = 1:70:778;
    flabs = zeros(length(fpoints),1);
    tlabs = zeros(length(tpoints),1);
    for labit = 1:length(fpoints)
        flabs(labit) = sprintf("%05d",  f(fpoints(labit))/ 1000);
        tlabs(labit) = sprintf("%0.4f", t(fpoints(labit)) * 1000);
    end
    yticks(fpoints)
    yticklabels( flabs);
    xticks(tpoints);
    xticklabels(tlabs);
    xlabel("Time (ms)")
    ylabel("Frequency (kHz)")
    tit = sprintf("Class %i",class_it-1);
    title(tit)
    colorbar
end %[output:group:7c3aa19f]
%%
%[text] ## K-NN Baseline
dat_train = squeeze(stft_feats(:,1:80,1));
dat_train(:,81:160) = squeeze(stft_feats(:,1:80,2));
train_labs = [zeros(1,80), ones(1,80)];

dat_test = squeeze(stft_feats(:,81:100,1));
dat_test(:,21:40) = squeeze(stft_feats(:,81:100,2));
test_labs = [zeros(1,20), ones(1,20)];

function f1 = getf1(results, labels)

    truepos  = sum( (results == 1) & (labels == 1));
    falsepos = sum( (results == 1) & (labels == 0));
    falseneg = sum( (results == 0) & (labels == 1));

    f1 = (2* truepos) / (2*truepos + falsepos + falseneg);

end


for k=1:50 %[output:group:42c70e60]
knnmodel = fitcknn( ...
        single(abs(dat_train))', ...
        single(train_labs), ...
        NumNeighbors=k, ...
        Standardize=1, ...
        Distance="cityblock" ...
        ) ;

train_res = predict(knnmodel, single(abs(dat_train))');
test_res = predict(knnmodel, single(abs(dat_test))');

train_acc = 100* sum(train_res' == train_labs) / length(train_labs);
test_acc = 100* sum(test_res' == test_labs) / length(test_labs);

fprintf("|| %2d || Acc %03.3f | %0.3f || F1 %0.3f | %0.3f ||\n", k, train_acc, test_acc, getf1(train_res',train_labs), getf1(test_res',test_labs)); %[output:7e91a2a1]
end %[output:group:42c70e60]
%%
%[text] ## SVM Baseline
svmmodel = fitcsvm(single(abs(dat_train))', single(train_labs)) %[output:6e0ecd54]
train_res = predict(svmmodel, single(abs(dat_train))');
test_res = predict(svmmodel, single(abs(dat_test))');

train_acc = 100* sum(train_res' == train_labs) / length(train_labs);
test_acc = 100* sum(test_res' == test_labs) / length(test_labs);

fprintf("||  Acc %03.3f | %0.3f || F1 %0.3f | %0.3f ||\n", train_acc, test_acc, getf1(train_res',train_labs), getf1(test_res',test_labs)); %[output:80e4496f]

